package com.ynxweb4.music;

import android.Manifest;
import android.app.*;
import android.content.*;
import android.graphics.Color;
import android.net.*;
import android.os.*;
import android.provider.Settings;
import android.view.*;
import android.widget.*;
import org.json.*;
import java.io.*;
import java.nio.file.Files;
import java.text.NumberFormat;
import java.time.Instant;
import java.time.format.DateTimeFormatter;
import java.util.*;

public final class MainActivity extends Activity {
    private static final int BLUE=Color.rgb(0,47,167), PICK_AUDIO=42;
    private LinearLayout content; private TextView status,now; private EditText search; private JSONObject state; private MusicStore store; private MusicApi api; private String view="home";
    @Override protected void attachBaseContext(Context base){super.attachBaseContext(LocaleSupport.wrap(base));}
    @Override public void onCreate(Bundle b){super.onCreate(b);store=new MusicStore(this);api=new MusicApi(this);state=store.load();build();handleCallback(getIntent());refresh();if(Build.VERSION.SDK_INT>=33&&checkSelfPermission(Manifest.permission.POST_NOTIFICATIONS)!=android.content.pm.PackageManager.PERMISSION_GRANTED)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},5);}
    @Override protected void onNewIntent(Intent i){super.onNewIntent(i);handleCallback(i);}
    private TextView text(String value,int sp){TextView v=new TextView(this);v.setText(value);v.setTextSize(sp);v.setTextColor(Color.rgb(7,18,46));v.setPadding(dp(12),dp(8),dp(12),dp(8));return v;}
    private Button button(String label){Button b=new Button(this);b.setText(label);b.setAllCaps(false);b.setContentDescription(label);return b;}
    private void build(){LinearLayout root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setBackgroundColor(Color.WHITE);TextView title=text(getString(R.string.app_name),24);title.setTextColor(BLUE);title.setTypeface(null,1);root.addView(title);Button wallet=button(getString(R.string.sign_in_wallet));wallet.setOnClickListener(v->wallet());root.addView(wallet);status=text(getString(R.string.loading),13);status.setAccessibilityLiveRegion(View.ACCESSIBILITY_LIVE_REGION_POLITE);root.addView(status);search=new EditText(this);search.setHint(R.string.search_hint);search.setSingleLine();search.setContentDescription(getString(R.string.search));search.setOnEditorActionListener((v,a,e)->{renderCatalog();return true;});root.addView(search,new LinearLayout.LayoutParams(-1,-2));LinearLayout nav=new LinearLayout(this);String[] labels={getString(R.string.home),getString(R.string.library),getString(R.string.creator),getString(R.string.settings)};String[] ids={"home","library","creator","settings"};for(int i=0;i<ids.length;i++){Button n=button(labels[i]);final String id=ids[i];n.setOnClickListener(v->{view=id;render();});nav.addView(n,new LinearLayout.LayoutParams(0,-2,1));}root.addView(nav);ScrollView scroll=new ScrollView(this);content=new LinearLayout(this);content.setOrientation(LinearLayout.VERTICAL);content.setPadding(dp(12),dp(8),dp(12),dp(120));scroll.addView(content);root.addView(scroll,new LinearLayout.LayoutParams(-1,0,1));LinearLayout player=new LinearLayout(this);player.setGravity(Gravity.CENTER_VERTICAL);now=text(getString(R.string.nothing_playing),16);player.addView(now,new LinearLayout.LayoutParams(0,-2,1));Button play=button(getString(R.string.play));play.setOnClickListener(v->startService(new Intent(this,PlaybackService.class).setAction(PlaybackService.PLAY)));Button pause=button(getString(R.string.pause));pause.setOnClickListener(v->startService(new Intent(this,PlaybackService.class).setAction(PlaybackService.PAUSE)));player.addView(play);player.addView(pause);root.addView(player);setContentView(root);}
    private void refresh(){status.setText(R.string.loading);new Thread(()->{try{JSONObject remote=api.get("/api/me");runOnUiThread(()->{state=merge(remote);status.setText(R.string.ready);render();});}catch(Exception e){runOnUiThread(()->{status.setText(getString(R.string.offline_mode)+": "+e.getMessage());render();});}}).start();}
    private JSONObject merge(JSONObject remote){try{state.put("remote",remote);store.save(state);}catch(Exception ignored){}return state;}
    private void render(){content.removeAllViews();if("settings".equals(view)){renderSettings();return;}if("creator".equals(view)){renderCreator();return;}if("library".equals(view)){heading(R.string.library);renderIds(state.optJSONArray("favorites"),getString(R.string.favorites));renderIds(state.optJSONArray("queue"),getString(R.string.queue));JSONObject remote=state.optJSONObject("remote"),listener=remote==null?null:remote.optJSONObject("listener");renderIds(listener==null?null:listener.optJSONArray("history"),getString(R.string.private_history));JSONObject downloads=state.optJSONObject("downloads");content.addView(text(getString(R.string.download_ready)+": "+(downloads==null?0:downloads.length()),14));Button playlist=button(getString(R.string.library)+" · "+getString(R.string.favorites));playlist.setOnClickListener(v->createPlaylist());content.addView(playlist);return;}renderCatalog();}
    private void renderCatalog(){content.removeAllViews();heading(R.string.catalog);JSONArray tracks=state.optJSONObject("remote")!=null?state.optJSONObject("remote").optJSONArray("catalog"):new JSONArray();String q=search.getText().toString().toLowerCase(Locale.ROOT);int shown=0;for(int i=0;i<tracks.length();i++){JSONObject t=tracks.optJSONObject(i);if(t==null)continue;String hay=t.optString("title")+" "+t.optString("artistName")+" "+t.optString("album");if(!q.isBlank()&&!hay.toLowerCase(Locale.ROOT).contains(q))continue;trackCard(t);shown++;}if(shown==0){content.addView(text(getString(tracks.length()==0?R.string.empty_catalog:R.string.no_search_results),16));Button retry=button(getString(R.string.retry));retry.setOnClickListener(v->refresh());content.addView(retry);}}
    private void trackCard(JSONObject t){LinearLayout card=new LinearLayout(this);card.setOrientation(LinearLayout.VERTICAL);card.setPadding(dp(12),dp(12),dp(12),dp(12));TextView name=text(t.optString("title")+" — "+t.optString("artistName"),18);name.setTypeface(null,1);name.setOnClickListener(v->new AlertDialog.Builder(this).setTitle(t.optString("title")).setMessage(t.optString("artistName")+"\n"+t.optString("album")+"\n"+getString(R.string.rights)+": "+t.optJSONObject("rights").optString("basis")+"\n"+getString(R.string.provenance)+": "+t.optJSONObject("provenance").optString("audio")).setPositiveButton(android.R.string.ok,null).show());card.addView(name);card.addView(text(getString(R.string.rights)+": "+t.optJSONObject("rights").optString("basis")+" · "+getString(R.string.provenance)+": "+t.optJSONObject("provenance").optString("audio"),12));LinearLayout actions=new LinearLayout(this);Button play=button(getString(R.string.play));play.setOnClickListener(v->play(t));Button fav=button(getString(R.string.favorite));fav.setOnClickListener(v->toggle("favorites",t.optString("id")));Button queue=button(getString(R.string.add_queue));queue.setOnClickListener(v->toggle("queue",t.optString("id")));Button dl=button(getString(R.string.download));dl.setOnClickListener(v->download(t));Button report=button(getString(R.string.rights));report.setOnClickListener(v->caseDialog(t));actions.addView(play);actions.addView(fav);actions.addView(queue);actions.addView(dl);actions.addView(report);card.addView(actions);content.addView(card);}
    private void play(JSONObject t){String id=t.optString("id"),uri=api.mediaURL(id);File local=store.offline(id);if(local.exists())uri=Uri.fromFile(local).toString();int pos=id.equals(state.optString("trackId"))?state.optInt("position"):0;Intent i=new Intent(this,PlaybackService.class).setAction(PlaybackService.PLAY).putExtra("trackId",id).putExtra("title",t.optString("title")).putExtra("uri",uri).putExtra("position",pos);if(Build.VERSION.SDK_INT>=26)startForegroundService(i);else startService(i);now.setText(t.optString("title"));}
    private void download(JSONObject t){status.setText(R.string.downloading);new Thread(()->{try{api.download(t.optString("id"));state.optJSONObject("downloads").put(t.optString("id"),"available");store.save(state);api.saveLibrary(state.optJSONArray("favorites"),state.optJSONArray("queue"),state.optJSONObject("downloads"));runOnUiThread(()->status.setText(R.string.download_ready));}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.download_failed)+": "+e.getMessage()));}}).start();}
    private void toggle(String key,String id){JSONArray a=state.optJSONArray(key);JSONArray next=new JSONArray();boolean found=false;for(int i=0;i<a.length();i++){String x=a.optString(i);if(x.equals(id))found=true;else next.put(x);}if(!found)next.put(id);try{state.put(key,next);store.save(state);}catch(Exception ignored){}render();new Thread(()->{try{api.saveLibrary(state.optJSONArray("favorites"),state.optJSONArray("queue"),state.optJSONObject("downloads"));}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.offline_mode)+": "+e.getMessage()));}}).start();}
    private void createPlaylist(){JSONArray ids=state.optJSONArray("favorites");if(ids==null||ids.length()==0){status.setText(R.string.empty_library);return;}EditText name=new EditText(this);name.setHint(R.string.library);new AlertDialog.Builder(this).setTitle(R.string.library).setView(name).setNegativeButton(R.string.cancel,null).setPositiveButton(R.string.upload,(d,w)->new Thread(()->{try{JSONObject p=api.createPlaylist(name.getText().toString(),ids);state.optJSONArray("playlists").put(p);store.save(state);runOnUiThread(()->status.setText(R.string.ready));}catch(Exception e){runOnUiThread(()->status.setText(e.getMessage()));}}).start()).show();}
    private void renderIds(JSONArray ids,String label){content.addView(text(label,18));if(ids==null||ids.length()==0){content.addView(text(getString(R.string.empty_library),14));return;}for(int i=0;i<ids.length();i++){Object value=ids.opt(i);content.addView(text(value instanceof JSONObject?((JSONObject)value).toString():String.valueOf(value),14));}}
    private void renderCreator(){heading(R.string.creator);content.addView(text(getString(R.string.creator_truth),14));Button pick=button(getString(R.string.upload_owned_audio));pick.setOnClickListener(v->startActivityForResult(new Intent(Intent.ACTION_OPEN_DOCUMENT).setType("audio/wav").addCategory(Intent.CATEGORY_OPENABLE),PICK_AUDIO));content.addView(pick);JSONObject remote=state.optJSONObject("remote");JSONArray tracks=remote==null?null:remote.optJSONArray("creatorTracks");if(tracks!=null)for(int i=0;i<tracks.length();i++){JSONObject t=tracks.optJSONObject(i);if(t==null)continue;Button release=button(t.optString("title")+" · "+t.optString("releaseState"));release.setEnabled("draft".equals(t.optString("releaseState")));release.setOnClickListener(v->release(t));content.addView(release);}JSONArray usage=remote==null?null:remote.optJSONArray("usage"),allocations=remote==null?null:remote.optJSONArray("allocations"),settlements=remote==null?null:remote.optJSONArray("settlements"),cases=remote==null?null:remote.optJSONArray("cases"),proposals=remote==null?null:remote.optJSONArray("aiProposals");content.addView(text(getString(R.string.usage_records)+": "+NumberFormat.getIntegerInstance().format(usage==null?0:usage.length()),14));content.addView(text(getString(R.string.revenue_truth),13));content.addView(text("YNX Pay: "+(settlements==null?0:settlements.length())+" · YNX Trust: "+(cases==null?0:cases.length())+" · AI: "+(proposals==null?0:proposals.length()),13));if(allocations!=null)for(int i=0;i<allocations.length();i++){JSONObject a=allocations.optJSONObject(i);Button pay=button("YNX Pay · "+a.optLong("amountMicros")+" µYNXT");pay.setOnClickListener(v->settle(a));content.addView(pay);}Button ai=button(getString(R.string.ai_enabled));ai.setEnabled(state.optBoolean("aiEnabled",true));ai.setOnClickListener(v->requestAI());content.addView(ai);content.addView(text(getString(R.string.ai_explanation),13));}
    private void requestAI(){JSONArray ids=state.optJSONArray("favorites");if(ids==null||ids.length()==0){status.setText(R.string.empty_library);return;}status.setText(R.string.loading);new Thread(()->{try{JSONObject p=api.createAI(ids,getSharedPreferences("settings",0).getString("aiLanguage","system"));api.streamAI(p.getString("id"));runOnUiThread(()->new AlertDialog.Builder(this).setTitle("YNX AI · "+p.optString("status")).setMessage(getString(R.string.ai_explanation)).setNegativeButton(R.string.cancel,(d,w)->reviewAI(p,"reject")).setPositiveButton(R.string.upload,(d,w)->reviewAI(p,"apply")).show());}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.retry)+": "+e.getMessage()));}}).start();}
    private void reviewAI(JSONObject p,String action){new Thread(()->{try{api.reviewAI(p.getString("id"),action,"AI reviewed library");runOnUiThread(()->{status.setText(R.string.ready);refresh();});}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.retry)+": "+e.getMessage()));}}).start();}
    private void release(JSONObject t){new Thread(()->{try{api.release(t.getString("id"),"published","");runOnUiThread(()->refresh());}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.retry)+": "+e.getMessage()));}}).start();}
    private void settle(JSONObject allocation){JSONObject remote=state.optJSONObject("remote"),profile=remote==null?null:remote.optJSONObject("profile");String account=profile==null?"":profile.optString("account");new Thread(()->{try{JSONObject intent=api.settlement(allocation.getString("id"),account);String review=intent.optString("reviewUri");runOnUiThread(()->{status.setText(intent.optString("status"));if(review.startsWith("ynxpay://"))startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse(review)));});}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.retry)+": "+e.getMessage()));}}).start();}
    private void caseDialog(JSONObject track){LinearLayout form=new LinearLayout(this);form.setOrientation(LinearLayout.VERTICAL);EditText reason=new EditText(this);reason.setHint(R.string.rights_declaration);EditText evidence=new EditText(this);evidence.setHint(R.string.rights_evidence);form.addView(reason);form.addView(evidence);new AlertDialog.Builder(this).setTitle(R.string.rights).setView(form).setNegativeButton(R.string.cancel,null).setPositiveButton(R.string.upload,(d,w)->new Thread(()->{try{api.openCase("dispute",track.optString("id"),reason.getText().toString(),evidence.getText().toString());runOnUiThread(()->{status.setText(R.string.ready);refresh();});}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.retry)+": "+e.getMessage()));}}).start()).show();}
    @Override protected void onActivityResult(int req,int result,Intent data){super.onActivityResult(req,result,data);if(req==PICK_AUDIO&&result==RESULT_OK&&data!=null)uploadDialog(data.getData());}
    private void uploadDialog(Uri uri){LinearLayout f=new LinearLayout(this);f.setOrientation(LinearLayout.VERTICAL);EditText title=new EditText(this);title.setHint(R.string.track_title);EditText artist=new EditText(this);artist.setHint(R.string.artist_name);EditText evidence=new EditText(this);evidence.setHint(R.string.rights_evidence);EditText provenance=new EditText(this);provenance.setHint(R.string.provenance);f.addView(title);f.addView(artist);f.addView(evidence);f.addView(provenance);new AlertDialog.Builder(this).setTitle(R.string.rights_declaration).setView(f).setNegativeButton(R.string.cancel,null).setPositiveButton(R.string.upload,(d,w)->new Thread(()->{try{File tmp=new File(getCacheDir(),"owned-upload.wav");try(InputStream in=getContentResolver().openInputStream(uri);OutputStream out=new FileOutputStream(tmp)){in.transferTo(out);}api.onboard(artist.getText().toString());api.upload(tmp,title.getText().toString(),artist.getText().toString(),"owned",evidence.getText().toString(),provenance.getText().toString());runOnUiThread(()->{status.setText(R.string.uploaded_draft);refresh();});}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.upload_failed)+": "+e.getMessage()));}}).start()).show();}
    private void renderSettings(){heading(R.string.settings);content.addView(text(getString(R.string.language),14));Spinner locales=new Spinner(this);ArrayAdapter<String>a=new ArrayAdapter<>(this,android.R.layout.simple_spinner_dropdown_item,LocaleSupport.TAGS);locales.setAdapter(a);String current=getSharedPreferences("settings",0).getString("locale","system");locales.setSelection(Math.max(0,Arrays.asList(LocaleSupport.TAGS).indexOf(current)));locales.setOnItemSelectedListener(new android.widget.AdapterView.OnItemSelectedListener(){boolean first=true;public void onNothingSelected(android.widget.AdapterView<?>p){}public void onItemSelected(android.widget.AdapterView<?>p,View v,int pos,long id){if(first){first=false;return;}LocaleSupport.set(MainActivity.this,LocaleSupport.TAGS[pos]);recreate();}});content.addView(locales);content.addView(text(getString(R.string.profile),14));JSONObject profile=state.optJSONObject("remote")==null?null:state.optJSONObject("remote").optJSONObject("profile");Switch explicit=new Switch(this);explicit.setText(R.string.explicit_content);explicit.setChecked(profile!=null&&profile.optBoolean("explicitAllowed"));Switch history=new Switch(this);history.setText(R.string.private_history);history.setChecked(profile==null||profile.optBoolean("privateHistory",true));CompoundButton.OnCheckedChangeListener saveProfile=(b,on)->saveProfile(explicit.isChecked(),history.isChecked());explicit.setOnCheckedChangeListener(saveProfile);history.setOnCheckedChangeListener(saveProfile);content.addView(explicit);content.addView(history);Switch ai=new Switch(this);ai.setText(R.string.ai_enabled);ai.setChecked(state.optBoolean("aiEnabled",true));ai.setOnCheckedChangeListener((b,on)->{try{state.put("aiEnabled",on);store.save(state);}catch(Exception ignored){}});content.addView(ai);content.addView(text(getString(R.string.ai_explanation),13));content.addView(text(getString(R.string.ai_output_language),14));Spinner aiLanguage=new Spinner(this);aiLanguage.setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_spinner_dropdown_item,LocaleSupport.TAGS));String aiTag=getSharedPreferences("settings",0).getString("aiLanguage","system");aiLanguage.setSelection(Math.max(0,Arrays.asList(LocaleSupport.TAGS).indexOf(aiTag)));aiLanguage.setOnItemSelectedListener(new android.widget.AdapterView.OnItemSelectedListener(){boolean first=true;public void onNothingSelected(android.widget.AdapterView<?>p){}public void onItemSelected(android.widget.AdapterView<?>p,View v,int pos,long id){if(first){first=false;return;}getSharedPreferences("settings",0).edit().putString("aiLanguage",LocaleSupport.TAGS[pos]).apply();}});content.addView(aiLanguage);Button clear=button(getString(R.string.clear_private_data));clear.setOnClickListener(v->new AlertDialog.Builder(this).setMessage(R.string.clear_confirm).setNegativeButton(R.string.cancel,null).setPositiveButton(R.string.delete,(d,w)->{SecureStore.clear(this);for(File f:getFilesDir().listFiles())f.delete();state=store.load();render();}).show());content.addView(clear);}
    private void saveProfile(boolean explicit,boolean privateHistory){JSONObject remote=state.optJSONObject("remote"),current=remote==null?null:remote.optJSONObject("profile");JSONObject p=new JSONObject();try{p.put("displayName",current==null?"YNX listener":current.optString("displayName","YNX listener")).put("bio",current==null?"":current.optString("bio")).put("explicitAllowed",explicit).put("privateHistory",privateHistory);}catch(Exception ignored){}new Thread(()->{try{JSONObject saved=api.updateProfile(p);if(remote!=null)remote.put("profile",saved);store.save(state);runOnUiThread(()->status.setText(R.string.ready));}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.retry)+": "+e.getMessage()));}}).start();}
    private void wallet(){try{String nonce=CentralContracts.nonce();getSharedPreferences("auth",0).edit().putString("nonce",nonce).putLong("expires",System.currentTimeMillis()+300000).apply();startActivity(new Intent(Intent.ACTION_VIEW,CentralContracts.walletAuthorization(nonce,System.currentTimeMillis())));}catch(Exception e){status.setText(getString(R.string.wallet_unavailable)+": "+e.getMessage());}}
    private void handleCallback(Intent i){Uri u=i.getData();if(u==null||!"ynxmusic".equals(u.getScheme()))return;String response=u.getQueryParameter("response"),nonce=getSharedPreferences("auth",0).getString("nonce","");long expiry=getSharedPreferences("auth",0).getLong("expires",0);getSharedPreferences("auth",0).edit().clear().apply();if(response==null||nonce.isBlank()||System.currentTimeMillis()>=expiry){status.setText(R.string.auth_rejected);return;}new Thread(()->{try{JSONObject result=api.post("/api/auth/wallet-v1/session",new JSONObject().put("response",response).put("expectedNonce",nonce).put("productClientId",CentralContracts.CLIENT).put("bundleId",CentralContracts.BUNDLE));SecureStore.put(this,result.getString("token"));runOnUiThread(()->{status.setText(R.string.authenticated);refresh();});}catch(Exception e){runOnUiThread(()->status.setText(getString(R.string.auth_rejected)+": "+e.getMessage()));}}).start();}
    private void heading(int id){TextView h=text(getString(id),26);h.setTextColor(BLUE);h.setTypeface(null,1);content.addView(h);}
    private int dp(int v){return Math.round(v*getResources().getDisplayMetrics().density);}
}
